export const INDEX_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n    <title>Boss Hog RBP Explorer</title>\n    <link rel=\"stylesheet\" href=\"/app/styles.css\">\n  </head>\n  <body>\n    <div class=\"page\">\n      <header class=\"hero\">\n        <div class=\"hero-brand\">\n          <img class=\"hero-logo\" src=\"/app/logo.png\" alt=\"Boss Hog logo\">\n          <div class=\"hero-heading\">\n            <p class=\"eyebrow\">Boss Hog</p>\n            <h1>Hog Price Prediction Explorer</h1>\n          </div>\n        </div>\n        <p class=\"hero-copy\">\n          Run the current USDA-backed monthly hog backtest in the browser.\n        </p>\n      </header>\n\n      <main class=\"layout\">\n        <section class=\"panel controls\">\n          <form id=\"controls-form\">\n            <div class=\"panel-heading\">\n              <h2>Controls</h2>\n            </div>\n\n            <label>\n              <span class=\"label-row\">Feature Pack <button class=\"info-button\" type=\"button\" data-info=\"feature-pack\">i</button></span>\n              <select name=\"feature_pack\">\n                <option value=\"price_only\">price_only</option>\n                <option value=\"core_fundamentals\">core_fundamentals</option>\n              </select>\n            </label>\n            <div class=\"info-panel\" id=\"feature-pack\" hidden>\n              <p class=\"info-summary\"><code>price_only</code> uses only price-derived features. <code>core_fundamentals</code> adds the same-report hog fundamentals.</p>\n              <button class=\"more-button\" type=\"button\" data-more-target=\"feature-pack-more\" aria-expanded=\"false\">More</button>\n              <div class=\"info-more\" id=\"feature-pack-more\" hidden>\n                <p>In simple terms, this setting decides whether the model looks only at price behavior or also at the physical hog-market details in the same USDA report. The deeper pack gives RBP more context for deciding which past months were truly similar.</p>\n              </div>\n            </div>\n\n            <label>\n              <span class=\"label-row\">Max Observations <button class=\"info-button\" type=\"button\" data-info=\"max-observations\">i</button></span>\n              <input name=\"max_observations\" type=\"number\" min=\"120\" max=\"300\" value=\"240\">\n            </label>\n            <div class=\"info-panel\" id=\"max-observations\" hidden>\n              <p class=\"info-summary\">How many recent monthly observations to keep before building the supervised dataset.</p>\n              <button class=\"more-button\" type=\"button\" data-more-target=\"max-observations-more\" aria-expanded=\"false\">More</button>\n              <div class=\"info-more\" id=\"max-observations-more\" hidden>\n                <p>This is the amount of history you let the backtest use. A larger number gives the model more past months to learn from, while a smaller number focuses it on the more recent market regime.</p>\n              </div>\n            </div>\n\n            <label>\n              <span class=\"label-row\">Initial Window <button class=\"info-button\" type=\"button\" data-info=\"initial-window\">i</button></span>\n              <input name=\"initial_window\" type=\"number\" min=\"60\" max=\"180\" value=\"120\">\n            </label>\n            <div class=\"info-panel\" id=\"initial-window\" hidden>\n              <p class=\"info-summary\">How many supervised rows are used before the first out-of-sample prediction.</p>\n              <button class=\"more-button\" type=\"button\" data-more-target=\"initial-window-more\" aria-expanded=\"false\">More</button>\n              <div class=\"info-more\" id=\"initial-window-more\" hidden>\n                <p>Think of this as the minimum amount of history the model needs before it starts making realistic test predictions. A bigger starting window usually means the early predictions are based on a fuller training sample.</p>\n              </div>\n            </div>\n\n            <label>\n              <span class=\"label-row\">Random Cells <button class=\"info-button\" type=\"button\" data-info=\"random-cells\">i</button></span>\n              <input name=\"random_cells\" type=\"number\" min=\"10\" max=\"40\" value=\"20\">\n            </label>\n            <div class=\"info-panel\" id=\"random-cells\" hidden>\n              <p class=\"info-summary\">How many additional sparse-grid cells RBP samples in each fit.</p>\n              <button class=\"more-button\" type=\"button\" data-more-target=\"random-cells-more\" aria-expanded=\"false\">More</button>\n              <div class=\"info-more\" id=\"random-cells-more\" hidden>\n                <p>RBP tries many small views of the data rather than one fixed equation. More random cells means it explores more combinations of variables and thresholds, which can help it catch structure but also takes longer to run.</p>\n              </div>\n            </div>\n\n            <label>\n              <span class=\"label-row\">Seed <button class=\"info-button\" type=\"button\" data-info=\"seed\">i</button></span>\n              <input name=\"seed\" type=\"number\" min=\"0\" max=\"9999\" value=\"11\">\n            </label>\n            <div class=\"info-panel\" id=\"seed\" hidden>\n              <p class=\"info-summary\">The sparse-grid sampler seed. Keep it fixed when you want comparable runs.</p>\n              <button class=\"more-button\" type=\"button\" data-more-target=\"seed-more\" aria-expanded=\"false\">More</button>\n              <div class=\"info-more\" id=\"seed-more\" hidden>\n                <p>The seed keeps the randomized parts of the RBP search repeatable. If you rerun with the same seed and same settings, you should get the same result instead of a slightly different sample of model cells.</p>\n              </div>\n            </div>\n\n            <button class=\"run-button\" type=\"submit\">Run Backtest</button>\n          </form>\n        </section>\n\n        <section class=\"results\">\n          <section class=\"status-bar\" id=\"status-bar\" aria-live=\"polite\">Loading default backtest...</section>\n          <section class=\"error-banner\" id=\"error-banner\" hidden></section>\n          <section id=\"results-root\"></section>\n        </section>\n      </main>\n    </div>\n\n    <script type=\"module\" src=\"/app/app.js\"></script>\n  </body>\n</html>\n";
export const APP_CSS = ":root {\n  --bg: #f4efe6;\n  --panel: #fffdf9;\n  --ink: #2c241a;\n  --muted: #6f6558;\n  --line: #dccfbd;\n  --accent: #8e4b2d;\n  --accent-strong: #6c2f16;\n  --accent-soft: #f0dfd4;\n  --shadow: 0 18px 42px rgba(69, 47, 27, 0.08);\n}\n\n* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  font-family: \"Avenir Next\", \"Trebuchet MS\", sans-serif;\n  color: var(--ink);\n  background:\n    radial-gradient(circle at top left, rgba(142, 75, 45, 0.12), transparent 24rem),\n    linear-gradient(180deg, #f8f3ec 0%, var(--bg) 100%);\n}\n\ncode {\n  font-family: \"SFMono-Regular\", \"Menlo\", monospace;\n  font-size: 0.95em;\n}\n\n.page {\n  max-width: 1160px;\n  margin: 0 auto;\n  padding: 32px 20px 56px;\n}\n\n.hero {\n  display: grid;\n  gap: 12px;\n  margin-bottom: 28px;\n}\n\n.hero-brand {\n  display: flex;\n  align-items: center;\n  gap: 18px;\n}\n\n.hero-heading {\n  display: grid;\n  gap: 8px;\n}\n\n.hero-logo {\n  width: clamp(92px, 11.5vw, 132px);\n  height: auto;\n  flex: none;\n  filter: drop-shadow(0 10px 20px rgba(69, 47, 27, 0.18));\n}\n\n.eyebrow {\n  margin: 0;\n  color: var(--accent);\n  font-size: 0.88rem;\n  font-weight: 700;\n  letter-spacing: 0.14em;\n  text-transform: uppercase;\n}\n\nh1,\nh2 {\n  margin: 0;\n  font-family: \"Iowan Old Style\", \"Palatino Linotype\", serif;\n}\n\nh1 {\n  font-size: clamp(2rem, 5vw, 3.5rem);\n  line-height: 1.02;\n  max-width: 11ch;\n}\n\n.hero-copy {\n  margin: 0;\n  max-width: 72ch;\n  color: var(--muted);\n  line-height: 1.6;\n}\n\n.layout {\n  display: grid;\n  grid-template-columns: minmax(280px, 340px) minmax(0, 1fr);\n  gap: 20px;\n}\n\n.panel {\n  background: var(--panel);\n  border: 1px solid var(--line);\n  border-radius: 20px;\n  box-shadow: var(--shadow);\n  padding: 20px;\n}\n\n.controls {\n  position: sticky;\n  top: 18px;\n  align-self: start;\n}\n\nform {\n  display: grid;\n  gap: 14px;\n}\n\nlabel {\n  display: grid;\n  gap: 8px;\n  font-size: 0.95rem;\n  font-weight: 700;\n}\n\ninput,\nselect,\n.run-button {\n  width: 100%;\n  border-radius: 12px;\n  border: 1px solid var(--line);\n  padding: 12px 14px;\n  background: #fff;\n  color: var(--ink);\n  font: inherit;\n}\n\n.run-button {\n  margin-top: 8px;\n  border: none;\n  background: linear-gradient(135deg, var(--accent), var(--accent-strong));\n  color: #fff;\n  font-weight: 700;\n  cursor: pointer;\n}\n\n.run-button:disabled {\n  cursor: wait;\n  opacity: 0.74;\n}\n\n.label-row {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.info-button {\n  width: 22px;\n  height: 22px;\n  border-radius: 999px;\n  border: 1px solid var(--line);\n  background: var(--accent-soft);\n  color: var(--accent-strong);\n  font-size: 0.78rem;\n  font-weight: 700;\n  cursor: pointer;\n}\n\n.info-panel {\n  margin-top: -4px;\n  padding: 10px 12px;\n  border-radius: 12px;\n  border: 1px dashed var(--line);\n  color: var(--muted);\n  background: rgba(239, 224, 216, 0.5);\n  font-size: 0.83rem;\n}\n\n.info-panel p {\n  margin: 0;\n  line-height: 1.5;\n}\n\n.info-summary + .more-button {\n  margin-top: 8px;\n}\n\n.more-button {\n  border: 0;\n  background: transparent;\n  color: var(--accent-strong);\n  font: inherit;\n  font-size: 0.8rem;\n  font-weight: 700;\n  padding: 0;\n  cursor: pointer;\n  text-decoration: underline;\n  text-underline-offset: 0.15em;\n}\n\n.info-more {\n  margin-top: 8px;\n}\n\n.results {\n  display: grid;\n  gap: 16px;\n}\n\n.status-bar,\n.error-banner {\n  border-radius: 14px;\n  padding: 12px 14px;\n  border: 1px solid var(--line);\n  background: var(--panel);\n}\n\n.status-content {\n  display: inline-flex;\n  align-items: center;\n  gap: 10px;\n}\n\n.status-bar--loading {\n  color: var(--accent-strong);\n}\n\n.status-spinner {\n  width: 28px;\n  height: 28px;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.status-spinner-logo {\n  width: 100%;\n  height: auto;\n  display: block;\n  animation: hog-spin 1.15s linear infinite;\n  transform-origin: center;\n  filter: drop-shadow(0 6px 10px rgba(69, 47, 27, 0.14));\n}\n\n.error-banner {\n  color: #8c1d1d;\n  background: #fff3f3;\n  border-color: #e6b5b5;\n}\n\n@keyframes hog-spin {\n  from {\n    transform: rotate(0deg);\n  }\n\n  to {\n    transform: rotate(360deg);\n  }\n}\n\n.results-grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));\n  gap: 14px;\n}\n\n.metric-card {\n  background: var(--panel);\n  border: 1px solid var(--line);\n  border-radius: 18px;\n  padding: 16px;\n  box-shadow: var(--shadow);\n}\n\n.metric-label,\n.detail-grid span {\n  color: var(--muted);\n  font-size: 0.88rem;\n}\n\n.metric-label {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.metric-value {\n  margin-top: 8px;\n  font-size: 1.8rem;\n  font-weight: 700;\n}\n\n.metric-value--small {\n  font-size: 1.05rem;\n  line-height: 1.35;\n}\n\n.metric-info-panel {\n  margin-top: 10px;\n}\n\n.detail-grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\n  gap: 12px;\n}\n\n.detail-grid div,\n.importance-list li {\n  padding: 14px;\n  border-radius: 14px;\n  background: #fff;\n  border: 1px solid var(--line);\n}\n\n.detail-grid strong {\n  display: block;\n  margin-top: 8px;\n  font-size: 1.1rem;\n}\n\n.panel-stack {\n  display: grid;\n  gap: 16px;\n}\n\n.importance-list {\n  list-style: none;\n  margin: 0;\n  padding: 0;\n  display: grid;\n  gap: 10px;\n}\n\n.importance-list li {\n  display: flex;\n  justify-content: space-between;\n  gap: 18px;\n  align-items: baseline;\n}\n\n.importance-list strong {\n  font-size: 1rem;\n}\n\n.importance-list span {\n  color: var(--muted);\n  font-variant-numeric: tabular-nums;\n}\n\n@media (max-width: 880px) {\n  .layout {\n    grid-template-columns: 1fr;\n  }\n\n  .controls {\n    position: static;\n  }\n\n  .hero-brand {\n    align-items: flex-start;\n    gap: 14px;\n  }\n\n  .hero-logo {\n    width: 110px;\n  }\n}\n";
export const APP_JS = "function escapeHtml(value) {\n  return String(value)\n    .replaceAll(\"&\", \"&amp;\")\n    .replaceAll(\"<\", \"&lt;\")\n    .replaceAll(\">\", \"&gt;\")\n    .replaceAll('\"', \"&quot;\")\n    .replaceAll(\"'\", \"&#39;\");\n}\n\nfunction importanceList(items) {\n  if (!items.length) {\n    return \"<p>No importance values were returned for this run.</p>\";\n  }\n  return `<ol class=\"importance-list\">${items\n    .map(\n      (item) =>\n        `<li><strong>${escapeHtml(item.feature)}</strong><span>${Number(item.importance).toFixed(4)}</span></li>`,\n    )\n    .join(\"\")}</ol>`;\n}\n\nfunction renderInfoPanel(id, summary, more) {\n  return `\n    <div class=\"info-panel metric-info-panel\" id=\"${escapeHtml(id)}\" hidden>\n      <p class=\"info-summary\">${escapeHtml(summary)}</p>\n      ${\n        more\n          ? `<button class=\"more-button\" type=\"button\" data-more-target=\"${escapeHtml(id)}-more\" aria-expanded=\"false\">More</button>\n             <div class=\"info-more\" id=\"${escapeHtml(id)}-more\" hidden>\n               <p>${escapeHtml(more)}</p>\n             </div>`\n          : \"\"\n      }\n    </div>\n  `;\n}\n\nfunction renderMetricCard({ label, value, valueClass = \"\", infoId, summary, more }) {\n  const metricValueClass = valueClass ? `metric-value ${valueClass}` : \"metric-value\";\n  return `\n    <article class=\"metric-card\">\n      <div class=\"metric-label\">\n        ${escapeHtml(label)}\n        <button class=\"info-button\" type=\"button\" data-info=\"${escapeHtml(infoId)}\" aria-expanded=\"false\">i</button>\n      </div>\n      <div class=\"${metricValueClass}\">${value}</div>\n      ${renderInfoPanel(infoId, summary, more)}\n    </article>\n  `;\n}\n\nfunction renderLoadingStatus(message) {\n  return `\n    <span class=\"status-content\">\n      <span class=\"status-spinner\" aria-hidden=\"true\">\n        <img class=\"status-spinner-logo\" src=\"/app/logo.png\" alt=\"\">\n      </span>\n      <span>${escapeHtml(message)}</span>\n    </span>\n  `;\n}\n\nexport function buildQuery(form) {\n  const params = new URLSearchParams();\n  const FormDataCtor = form.ownerDocument?.defaultView?.FormData ?? FormData;\n  const entries = new FormDataCtor(form);\n  for (const [key, value] of entries.entries()) {\n    params.set(key, String(value));\n  }\n  return params.toString();\n}\n\nexport function renderResults(payload) {\n  const metrics = payload.metrics;\n  const finalMonth = payload.final_month;\n  const dataStatus = payload.data_status;\n\n  return `\n    <div class=\"results-grid\">\n      ${renderMetricCard({\n        label: \"Prediction / Actual Correlation\",\n        value: Number(metrics.prediction_actual_correlation).toFixed(3),\n        infoId: \"corr-info\",\n        summary: \"Correlation between predicted and realized next-month log returns over the out-of-sample window.\",\n        more: \"In simple terms, this asks whether the model tended to move in the same direction as reality over time. A higher positive value means the forecasts tracked the actual pattern better, while a value near zero means they were not lining up much at all.\",\n      })}\n      ${renderMetricCard({\n        label: \"Directional Accuracy\",\n        value: Number(metrics.directional_accuracy).toFixed(3),\n        infoId: \"direction-info\",\n        summary: \"Share of out-of-sample months where the sign of the predicted move matched the sign of the realized move.\",\n        more: \"This ignores the exact size of the forecast and asks a simpler yes-or-no question: did the model get up versus down right? It is useful when direction matters more than perfect magnitude.\",\n      })}\n      ${renderMetricCard({\n        label: \"Average Ex-Ante Fit\",\n        value: Number(metrics.average_ex_ante_fit).toFixed(3),\n        infoId: \"fit-info\",\n        summary: \"RBP's internal reliability score averaged across the rolling predictions. Higher is better, but it is not the same thing as realized forecast accuracy.\",\n        more: \"This is the model's own estimate of how trustworthy each prediction looked before the future happened. It is useful as a confidence signal, but a confident forecast can still turn out wrong.\",\n      })}\n      ${renderMetricCard({\n        label: \"Feature Pack\",\n        value: escapeHtml(metrics.feature_pack),\n        valueClass: \"metric-value--small\",\n        infoId: \"pack-info\",\n        summary: \"The set of inputs included in each monthly RBP feature row. price_only uses only price-derived signals; core_fundamentals also adds same-report hog fundamentals.\",\n        more: \"This setting changes what the model is allowed to consider when it searches for relevant past months. The broader pack adds more economic context from the same USDA report, not a different model.\",\n      })}\n    </div>\n\n    <div class=\"panel-stack\">\n      <section class=\"panel\">\n        <div class=\"panel-heading\">\n          <h2>Data Status</h2>\n        </div>\n        <div class=\"detail-grid\">\n          <div><span>Source</span><strong>${escapeHtml(dataStatus.source)}</strong></div>\n          <div><span>Purchase Type</span><strong>${escapeHtml(dataStatus.purchase_type)}</strong></div>\n          <div><span>Data As Of</span><strong>${escapeHtml(dataStatus.data_as_of)}</strong></div>\n          <div><span>Refreshed At</span><strong>${escapeHtml(dataStatus.refreshed_at)}</strong></div>\n        </div>\n      </section>\n\n      <section class=\"panel\">\n        <div class=\"panel-heading\">\n          <h2>Final Out-of-Sample Month</h2>\n        </div>\n        <div class=\"detail-grid\">\n          <div><span>Predicted Month</span><strong>${escapeHtml(finalMonth.prediction_date)}</strong></div>\n          <div><span>Predicted Next-Month Log Return</span><strong>${Number(finalMonth.predicted_next_month_log_return).toFixed(4)}</strong></div>\n          <div><span>Actual Next-Month Log Return</span><strong>${Number(finalMonth.actual_next_month_log_return).toFixed(4)}</strong></div>\n          <div><span>Starting Month Price Average</span><strong>${Number(finalMonth.starting_month_price_average).toFixed(2)}</strong></div>\n          <div><span>Predicted Next Month Price Average</span><strong>${Number(finalMonth.predicted_next_month_price_average).toFixed(2)}</strong></div>\n          <div><span>Actual Next Month Price Average</span><strong>${Number(finalMonth.actual_next_month_price_average).toFixed(2)}</strong></div>\n        </div>\n      </section>\n\n      <section class=\"panel\">\n        <div class=\"panel-heading\">\n          <h2>Average Feature Importance</h2>\n        </div>\n        ${importanceList(payload.average_feature_importance)}\n      </section>\n\n      ${\n        payload.average_exogenous_importance.length\n          ? `<section class=\"panel\">\n               <div class=\"panel-heading\">\n                 <h2>Average Exogenous Importance</h2>\n               </div>\n               ${importanceList(payload.average_exogenous_importance)}\n             </section>`\n          : \"\"\n      }\n    </div>\n  `;\n}\n\nexport function wireInfoButtons(root) {\n  for (const button of root.querySelectorAll(\"[data-info]\")) {\n    button.addEventListener(\"click\", () => {\n      const panel = findPanel(root, button.dataset.info);\n      if (!panel) {\n        return;\n      }\n      const isOpen = !panel.hidden;\n      panel.hidden = isOpen;\n      if (isOpen) {\n        for (const moreButton of panel.querySelectorAll(\"[data-more-target]\")) {\n          const morePanel = root.getElementById(moreButton.dataset.moreTarget);\n          if (morePanel) {\n            morePanel.hidden = true;\n          }\n          moreButton.textContent = \"More\";\n          moreButton.setAttribute(\"aria-expanded\", \"false\");\n        }\n      }\n    });\n  }\n\n  for (const button of root.querySelectorAll(\"[data-more-target]\")) {\n    button.addEventListener(\"click\", () => {\n      const panel = findPanel(root, button.dataset.moreTarget);\n      if (!panel) {\n        return;\n      }\n      const willOpen = panel.hidden;\n      panel.hidden = !willOpen;\n      button.textContent = willOpen ? \"Less\" : \"More\";\n      button.setAttribute(\"aria-expanded\", willOpen ? \"true\" : \"false\");\n    });\n  }\n}\n\nfunction findPanel(root, id) {\n  if (!id) {\n    return null;\n  }\n  if (typeof root.getElementById === \"function\") {\n    return root.getElementById(id);\n  }\n  return root.querySelector(`#${id}`);\n}\n\nexport async function runBacktest({ form, statusBar, errorBanner, resultsRoot, submitButton, fetchImpl = fetch }) {\n  const query = buildQuery(form);\n  statusBar.innerHTML = renderLoadingStatus(\"Running backtest...\");\n  statusBar.classList.add(\"status-bar--loading\");\n  errorBanner.hidden = true;\n  submitButton.disabled = true;\n  try {\n    const response = await fetchImpl(`/api/backtest?${query}`, {\n      headers: { accept: \"application/json\" },\n    });\n    const payload = await response.json();\n    if (!response.ok) {\n      throw new Error(payload.error || \"Backtest failed.\");\n    }\n    resultsRoot.innerHTML = renderResults(payload);\n    wireInfoButtons(resultsRoot);\n    statusBar.textContent = \"Backtest complete.\";\n    statusBar.classList.remove(\"status-bar--loading\");\n  } catch (error) {\n    errorBanner.hidden = false;\n    errorBanner.textContent = error instanceof Error ? error.message : String(error);\n    statusBar.textContent = \"Backtest failed.\";\n    statusBar.classList.remove(\"status-bar--loading\");\n  } finally {\n    submitButton.disabled = false;\n  }\n}\n\nexport function boot(doc = document, fetchImpl = fetch) {\n  const form = doc.getElementById(\"controls-form\");\n  const statusBar = doc.getElementById(\"status-bar\");\n  const errorBanner = doc.getElementById(\"error-banner\");\n  const resultsRoot = doc.getElementById(\"results-root\");\n  const submitButton = form.querySelector(\"button[type='submit']\");\n\n  wireInfoButtons(doc);\n  form.addEventListener(\"submit\", async (event) => {\n    event.preventDefault();\n    await runBacktest({ form, statusBar, errorBanner, resultsRoot, submitButton, fetchImpl });\n  });\n  return runBacktest({ form, statusBar, errorBanner, resultsRoot, submitButton, fetchImpl });\n}\n\nif (typeof window !== \"undefined\" && window.document) {\n  void boot(window.document, window.fetch.bind(window));\n}\n";
export const LOGO_PNG_BASE64 = "";
